// Without a container. `main.dart` becomes THE ONE PLACE that knows all wiring.
// This works fine for small apps.

void main() {
  // 1. Instantiate the outermost dependencies.
  final dio = Dio(BaseOptions(baseUrl: 'https://api.example.com'));
  final hiveBox = Hive.box<Map>('users');

  // 2. Compose upward — data sources → repository → use case → view model.
  final remote = UserRemoteDataSource(dio);
  final local  = UserLocalDataSource(hiveBox);
  final repo   = UserRepositoryImpl(remote, local);
  final registerUser = RegisterUser(repo);
  final loginVm = LoginViewModel(registerUser);

  // 3. Hand the root VM to the app.
  runApp(MyApp(loginVm: loginVm));
}

// The whole graph is visible in one file. That's the 'composition root'.
// Testable? Yes — swap `dio` and `hiveBox` for fakes at the top.
// Scaling? OK for maybe 30 classes. Beyond that, use a container.

// pubspec: get_it: ^7.7.0
import 'package:get_it/get_it.dart';

final getIt = GetIt.instance;

// Register everything at startup — the composition root.
void setupServiceLocator() {
  getIt.registerSingleton<Dio>(Dio(BaseOptions(baseUrl: 'https://api.example.com')));
  getIt.registerSingleton<Box<Map>>(Hive.box<Map>('users'));

  getIt.registerFactory<UserRemoteDataSource>(() => UserRemoteDataSource(getIt<Dio>()));
  getIt.registerFactory<UserLocalDataSource>(() => UserLocalDataSource(getIt<Box<Map>>()));

  getIt.registerLazySingleton<UserRepository>(() => UserRepositoryImpl(
    getIt<UserRemoteDataSource>(),
    getIt<UserLocalDataSource>(),
  ));

  getIt.registerFactory<RegisterUser>(() => RegisterUser(getIt<UserRepository>()));
}

void main() {
  setupServiceLocator();
  runApp(const MyApp());
}

// Elsewhere in the app — grab any dependency by TYPE:
final registerUser = getIt<RegisterUser>();   // no BuildContext, no boilerplate.
// Trade-off: hidden coupling — grep is your only tool to see who uses what.

// pubspec: flutter_riverpod: ^2.5.1
import 'package:flutter_riverpod/flutter_riverpod.dart';

// Each provider IS a DI registration — top-level `final`.
final dioProvider = Provider<Dio>((ref) => Dio());
final hiveBoxProvider = Provider<Box<Map>>((ref) => Hive.box<Map>('users'));

final userRemoteProvider = Provider<UserRemoteDataSource>(
  (ref) => UserRemoteDataSource(ref.read(dioProvider)),
);
final userLocalProvider = Provider<UserLocalDataSource>(
  (ref) => UserLocalDataSource(ref.read(hiveBoxProvider)),
);

final userRepositoryProvider = Provider<UserRepository>(
  (ref) => UserRepositoryImpl(
    ref.read(userRemoteProvider),
    ref.read(userLocalProvider),
  ),
);

final registerUserProvider = Provider<RegisterUser>(
  (ref) => RegisterUser(ref.read(userRepositoryProvider)),
);

// In ViewModel / widget:
final registerUser = ref.read(registerUserProvider);

// Trade-off vs get_it: compile-safe (missing provider = build error),
//   test-friendly (override providers in ProviderScope for tests),
//   no `BuildContext` required, tracks lifecycle.
